- "beacons of light" metaphorically refers to campaigns;
- "still burning brightly" indicates the campaigns are active;
- "attracted more than 10,000 admirers" translates to campaigns receiving more than 10,000 views.

sql:
SELECT c.campaign_id, cc.category_name 
FROM campaigns c
INNER JOIN campaign_categories cc ON c.campaign_category_id = cc.category_id;

SELECT campaign_id, value
FROM campaigns
WHERE value = (SELECT MAX(value) FROM campaigns);

SELECT campaign_id, revenue
FROM campaign_performance
WHERE revenue > 500;

